/**
 * @fileoverview Shared timing constants — delays, durations, debounce defaults.
 *
 * Centralizes common timing values that appear across multiple components
 * to ensure consistency and eliminate magic numbers.
 *
 * @module shared/tokens/timing
 */

/** Default debounce delay (ms) — used by razyui.debounce() and several components. */
export const DEFAULT_DEBOUNCE_MS = 300;

/**
 * Blur/focus delay (ms) — short pause before closing a dropdown on blur,
 * allowing click events on dropdown items to register first.
 * Used by: ClipBox, DynamicSearch, Combobox, TreeView.
 */
export const BLUR_CLOSE_DELAY_MS = 150;

/** Standard transition / animation fallback duration (ms). */
export const TRANSITION_DURATION_MS = 300;
